INSERT INTO `tour_route` VALUES (1,1,1,'郑州-洛阳两日文化游','http://127.0.0.1:8080/uploads/20260317-86f95f2511714361a343103682858bf5.png','二七纪念塔+河南省博物院+龙门石窟+白马寺','含住宿与门票，适合家庭及学生群体\n\n[[YUTU_ROUTE_META]]\n{\"relatedImages\":[\"http://127.0.0.1:8080/uploads/20260317-450ef3c104fe44bea0570c7f5c216ef8.jpeg\",\"http://127.0.0.1:8080/uploads/20260317-00ddd80959b3439a8e57e35172e4509a.jpeg\",\"http://127.0.0.1:8080/uploads/20260317-5e109ca75f1946ec868453d5ba1c630c.jpeg\",\"http://127.0.0.1:8080/uploads/20260317-286fbe3367f94923853f048e95bfbe88.jpeg\"]}',699.00,100,4.9,1,NULL,1,1,0,'2026-03-14 13:18:27','2026-03-17 16:29:57'),(2,1,1,'嵩山少林一日游','http://127.0.0.1:8080/uploads/20260317-4dff972b2e804483bd39b2e8b606b545.jpeg','少林寺+塔林+武术表演','含往返交通与导游服务\n\n[[YUTU_ROUTE_META]]\n{\"relatedImages\":[\"http://127.0.0.1:8080/uploads/20260317-0bb81d14876541b697b1df492f48197f.jpeg\",\"http://127.0.0.1:8080/uploads/20260317-e0e554a2077242678094f4aa1e0c933c.jpeg\",\"http://127.0.0.1:8080/uploads/20260317-dcab1984ecd24eeb8fb50c7d232ca8e9.jpeg\"]}',299.00,120,4.0,1,NULL,1,1,0,'2026-03-14 13:18:27','2026-03-17 10:57:13'),(3,2,1,'只有河南戏剧幻城一日游','http://127.0.0.1:8080/uploads/20260317-5374014be4564c45aa9f2375cc608288.jpg','中牟县只有河南戏剧幻城','上午九点郑州火车站出发，前往中牟县只有河南戏剧幻城，下午五点返回郑州。\n\n[[YUTU_ROUTE_META]]\n{\"relatedImages\":[\"http://127.0.0.1:8080/uploads/20260317-3abc529e77be4eefa4659578a020bc24.jpeg\",\"http://127.0.0.1:8080/uploads/20260317-32a1d846e7cc4958afac8f9e51a095c8.jpg\",\"http://127.0.0.1:8080/uploads/20260317-6745eb5e4c654c129ccbc4294e7d5f5b.jpeg\"]}',499.00,50,5.0,1,NULL,1,1,0,'2026-03-17 16:49:28','2026-03-18 17:09:05');
